define("quiz_paperentry/settings_picker",[],(function(){"use strict";return{init:function(savedfields,availablelabels){var picker=document.getElementById("settings-field-picker"),tagArea=document.getElementById("settings-field-tags"),hiddenDiv=document.getElementById("settings-hidden-inputs");if(!picker)return;function addTag(key,label,removefromlist){var tag=document.createElement("span");tag.className="badge badge-secondary d-inline-flex align-items-center";tag.style.cssText="font-size:.85rem;padding:.35em .6em;gap:4px";tag.dataset.key=key;var text=document.createTextNode(label+" "),del=document.createElement("button");del.type="button";del.innerHTML="&times;";del.title="Remove";del.style.cssText="background:none;border:none;color:inherit;padding:0;line-height:1;font-size:1rem;cursor:pointer;margin-left:2px";del.addEventListener("click",(function(){var opt=document.createElement("option");opt.value=key;opt.text=label;picker.appendChild(opt);var inp=hiddenDiv.querySelector('input[value="'+key+'"]');inp&&inp.remove();tag.remove()}));tag.appendChild(text);tag.appendChild(del);tagArea.appendChild(tag);var hidden=document.createElement("input");hidden.type="hidden";hidden.name="extrafields[]";hidden.value=key;hiddenDiv.appendChild(hidden);if(removefromlist)for(var i=0;i<picker.options.length;i++)if(picker.options[i].value===key){picker.remove(i);break}}savedfields.forEach((function(key){addTag(key,availablelabels[key]||key,false)}));picker.addEventListener("change",(function(){var key=this.value,label=this.options[this.selectedIndex].text;if(key){this.remove(this.selectedIndex);this.value="";addTag(key,label,false)}}))}};}));
